1	export interface ItemSpec {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: ItemSpec[];
15	}
16	
17	export interface QuoteResult {
18	  premium: number;
19	}
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const BLOCK_SIZE = 3;
27	const BLOCK_PRICE = 60;
28	const COMPONENT_TYPES = ["rune", "moonstone"];
29	
30	const BASE_PREMIUMS: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	  moonstone: 25,
37	};
38	
39	function basePremiumFor(item: ItemSpec): number {
40	  return BASE_PREMIUMS[item.type] ?? 0;
41	}
42	
43	function sumBasePremiums(items: ItemSpec[]): number {
44	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
45	}
46	
47	function countItemsOfType(items: ItemSpec[], type: string): number {
48	  return items.filter((item) => item.type === type).length;
49	}
50	
51	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
52	  const count = countItemsOfType(items, componentType);
53	  if (count !== BLOCK_SIZE) return 0;
54	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
55	}
56	
57	function blockAdjustment(items: ItemSpec[]): number {
58	  return COMPONENT_TYPES.reduce(
59	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
60	    0
61	  );
62	}
63	
64	function isHighlyEnchanted(item: ItemSpec): boolean {
65	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
66	}
67	
68	function itemSurchargeFor(item: ItemSpec): number {
69	  let surcharge = 0;
70	  if (item.cursed) surcharge += basePremiumFor(item) * CURSE_SURCHARGE_RATE;
71	  if (isHighlyEnchanted(item)) surcharge += basePremiumFor(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
72	  return surcharge;
73	}
74	
75	function sumItemSurcharges(items: ItemSpec[]): number {
76	  return items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
77	}
78	
79	export function quote(input: QuoteInput): QuoteResult {
80	  const items = input.items;
81	  const policyBasePremium = sumBasePremiums(items) + blockAdjustment(items);
82	  const itemSurcharges = sumItemSurcharges(items);
83	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
84	  return {
85	    premium: Math.ceil(
86	      policyBasePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE
87	    ),
88	  };
89	}
90	
91	export function claim(): unknown {
92	  return undefined;
93	}
